head.script:
scwin.vCurDate = "";
scwin.vStartDate = "";
scwin.vFirstDate = "";
scwin.em_adptYm = "";

scwin.onpageload = function() {
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.vStartDate = $c.date.addDate(scwin.vCurDate, -2);
    scwin.vFirstDate = scwin.vCurDate.substring(0, 6) + "01";
    scwin.em_adptYm = scwin.vCurDate.substring(0, 6);
};

scwin.onUdcCompleted = function() {
    udc_rsltsStdDt.setInitDate(scwin.vCurDate, scwin.vCurDate);
};

scwin.btn_Srch_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.btn_upload_sample_onclick = function(e) {
    scwin.f_sample();
};

scwin.btn_save_onclick = function(e) {
    scwin.f_Save();
};

scwin.btn_delete_onclick = function(e) {
    scwin.f_Delete();
};

scwin.btn_apply_onclick = function(e) {
    scwin.f_Apply();
};

scwin.f_sample = function() {
    let fileName = "운송임및비용등록(일괄)_SAMPLE.csv";
    let filePath = "ja/dn/workrslts/운송임및비용등록(일괄)_SAMPLE.csv";
    $c.gus.cfDownloadFile(fileName, filePath);
};

scwin.f_Upload = function() {
    ds_results.removeAll();
    ds_Tmp_FillUse.removeAll();
    ds_330_FillUse.removeAll();
    // TODO: 엑셀 업로드 처리 - cfDrmUploadFile / fileUploadGDS 기반 업로드는 WebSquare 파일업로드 컴포넌트로 대체 필요
    $c.gus.cfProgressWinOpen();
    $p.setTimeout(function() {
        scwin.f_Import();
    }, {"delay": 1000});
};

scwin.f_Import = async function() {
    $c.gus.cfProgressWinClose();

    let amt10, etcSum;
    let altMsg = "";

    for (let i = 0; i < ds_Tmp_FillUse.getRowCount(); i++) {
        amt10 = 0;
        etcSum = 0;

        if (ds_Tmp_FillUse.getCellData(i, "rsltsStdDt") == "") {
            continue;
        }

        let newRow = ds_results.insertRow();

        ds_results.setCellData(newRow, "rsltsStdDt", ds_Tmp_FillUse.getCellData(i, "rsltsStdDt"));
        ds_results.setCellData(newRow, "vehclNo", ds_Tmp_FillUse.getCellData(i, "vehclNo"));
        ds_results.setCellData(newRow, "homeClntNo", ds_Tmp_FillUse.getCellData(i, "homeClntNo"));
        ds_results.setCellData(newRow, "clntNo", ds_Tmp_FillUse.getCellData(i, "clntNo"));
        ds_results.setCellData(newRow, "clntNm", ds_Tmp_FillUse.getCellData(i, "clntNm"));

        ds_results.setCellData(newRow, "amt01", ds_Tmp_FillUse.getCellData(i, "amt01"));
        ds_results.setCellData(newRow, "amt02", ds_Tmp_FillUse.getCellData(i, "amt02"));
        ds_results.setCellData(newRow, "amt03", ds_Tmp_FillUse.getCellData(i, "amt03"));
        ds_results.setCellData(newRow, "amt04", ds_Tmp_FillUse.getCellData(i, "amt04"));
        ds_results.setCellData(newRow, "amt05", ds_Tmp_FillUse.getCellData(i, "amt05"));
        ds_results.setCellData(newRow, "amt06", ds_Tmp_FillUse.getCellData(i, "amt06"));
        ds_results.setCellData(newRow, "amt07", ds_Tmp_FillUse.getCellData(i, "amt07"));
        ds_results.setCellData(newRow, "amt08", ds_Tmp_FillUse.getCellData(i, "amt08"));
        ds_results.setCellData(newRow, "amt09", ds_Tmp_FillUse.getCellData(i, "amt09"));
        ds_results.setCellData(newRow, "amt10", ds_Tmp_FillUse.getCellData(i, "amt10"));
        amt10 = Number(ds_Tmp_FillUse.getCellData(i, "amt10"));
        ds_results.setCellData(newRow, "amt11", ds_Tmp_FillUse.getCellData(i, "amt11"));
        ds_results.setCellData(newRow, "amt12", ds_Tmp_FillUse.getCellData(i, "amt12"));
        ds_results.setCellData(newRow, "amt13", ds_Tmp_FillUse.getCellData(i, "amt13"));
        ds_results.setCellData(newRow, "amt14", ds_Tmp_FillUse.getCellData(i, "amt14"));
        ds_results.setCellData(newRow, "amt15", ds_Tmp_FillUse.getCellData(i, "amt15"));
        ds_results.setCellData(newRow, "amt16", ds_Tmp_FillUse.getCellData(i, "amt16"));
        ds_results.setCellData(newRow, "amt17", ds_Tmp_FillUse.getCellData(i, "amt17"));
        ds_results.setCellData(newRow, "amt18", ds_Tmp_FillUse.getCellData(i, "amt18"));
        ds_results.setCellData(newRow, "amt19", ds_Tmp_FillUse.getCellData(i, "amt19"));

        ds_results.setCellData(newRow, "etc01", ds_Tmp_FillUse.getCellData(i, "etc01"));
        etcSum += Number(ds_Tmp_FillUse.getCellData(i, "etc01"));
        ds_results.setCellData(newRow, "etc02", ds_Tmp_FillUse.getCellData(i, "etc02"));
        etcSum += Number(ds_Tmp_FillUse.getCellData(i, "etc02"));
        ds_results.setCellData(newRow, "etc03", ds_Tmp_FillUse.getCellData(i, "etc03"));
        etcSum += Number(ds_Tmp_FillUse.getCellData(i, "etc03"));
        ds_results.setCellData(newRow, "etc04", ds_Tmp_FillUse.getCellData(i, "etc04"));
        etcSum += Number(ds_Tmp_FillUse.getCellData(i, "etc04"));
        ds_results.setCellData(newRow, "etc05", ds_Tmp_FillUse.getCellData(i, "etc05"));
        etcSum += Number(ds_Tmp_FillUse.getCellData(i, "etc05"));
        ds_results.setCellData(newRow, "etc06", ds_Tmp_FillUse.getCellData(i, "etc06"));
        etcSum += Number(ds_Tmp_FillUse.getCellData(i, "etc06"));
        ds_results.setCellData(newRow, "etc07", ds_Tmp_FillUse.getCellData(i, "etc07"));
        etcSum += Number(ds_Tmp_FillUse.getCellData(i, "etc07"));
        ds_results.setCellData(newRow, "etc08", ds_Tmp_FillUse.getCellData(i, "etc08"));
        etcSum += Number(ds_Tmp_FillUse.getCellData(i, "etc08"));
        ds_results.setCellData(newRow, "etc09", ds_Tmp_FillUse.getCellData(i, "etc09"));
        etcSum += Number(ds_Tmp_FillUse.getCellData(i, "etc09"));
        ds_results.setCellData(newRow, "etc10", ds_Tmp_FillUse.getCellData(i, "etc10"));
        etcSum += Number(ds_Tmp_FillUse.getCellData(i, "etc10"));
        ds_results.setCellData(newRow, "etc11", ds_Tmp_FillUse.getCellData(i, "etc11"));
        etcSum += Number(ds_Tmp_FillUse.getCellData(i, "etc11"));
        ds_results.setCellData(newRow, "etc12", ds_Tmp_FillUse.getCellData(i, "etc12"));
        etcSum += Number(ds_Tmp_FillUse.getCellData(i, "etc12"));
        ds_results.setCellData(newRow, "etc13", ds_Tmp_FillUse.getCellData(i, "etc13"));
        etcSum += Number(ds_Tmp_FillUse.getCellData(i, "etc13"));
        ds_results.setCellData(newRow, "etc14", ds_Tmp_FillUse.getCellData(i, "etc14"));
        etcSum += Number(ds_Tmp_FillUse.getCellData(i, "etc14"));
        ds_results.setCellData(newRow, "etc15", ds_Tmp_FillUse.getCellData(i, "etc15"));
        etcSum += Number(ds_Tmp_FillUse.getCellData(i, "etc15"));
        ds_results.setCellData(newRow, "etc16", ds_Tmp_FillUse.getCellData(i, "etc16"));
        etcSum += Number(ds_Tmp_FillUse.getCellData(i, "etc16"));
        ds_results.setCellData(newRow, "etc17", ds_Tmp_FillUse.getCellData(i, "etc17"));
        etcSum += Number(ds_Tmp_FillUse.getCellData(i, "etc17"));

        if (amt10 != etcSum) {
            if (altMsg != "") {
                altMsg += ", ";
            }
            altMsg = (i + 1);
        }
    }

    if (altMsg != "") {
        await $c.win.alert(altMsg + "열의 기타매출액과 기타매출상세의 합이 일치하지 않습니다.");
    }

    ds_Tmp_FillUse.removeAll();
    spa_totalRow.setValue(ds_results.getTotalRow());
};

scwin.f_CheckFileExt = async function(ext, path) {
    ext = ext.toUpperCase();
    path = path.toUpperCase();
    let elen = ext.length;
    let flen = path.length;
    return (ext == path.substring((flen - elen), flen));
};

scwin.f_Retrieve = async function() {
    scwin.f_ProcessBinding();

    if (dma_condition.get("rsltsStdDtSt") == "" || dma_condition.get("rsltsStdDtEnd") == "") {
        await $c.win.alert("실적기간은 필수 입력 항목입니다.");
        return false;
    }
    if (!$c.gus.cfIsAfterDate(dma_condition.get("rsltsStdDtSt"), dma_condition.get("rsltsStdDtEnd"))) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        return;
    }

    await $c.sbm.execute(sbm_retrieve);
};

scwin.f_ProcessBinding = async function() {
    dma_condition.set("homeClntNo", ed_homeClntNo.getValue());
    dma_condition.set("clntNo", ed_clntNo.getValue());
    dma_condition.set("rsltsStdDtSt", ica_rsltsStdDtSt.getValue());
    dma_condition.set("rsltsStdDtEnd", ica_rsltsStdDtEnd.getValue());
    dma_condition.set("vehclNo", txt_vehclNo.getValue());
};

scwin.f_Save = async function() {
    let checkedCnt = 0;

    for (let i = 0; i < ds_results.getRowCount(); i++) {
        if (ds_results.getRowStatus(i) == "C") {
            if (!$c.gus.cfValidateValue(ds_results.getCellData(i, "rsltsStdDt"), "date=YYYYMMDD")) {
                await $c.gus.cfAlertMsg((i + 1) + "번째 데이터의 실적일자는 유효한 날짜 형식이 아닙니다.");
                return;
            }
            if (ds_results.getCellData(i, "rsltsStdDt") == "") {
                await $c.win.alert((i + 1) + "행의 실적일자는 필수 입력 항목 입니다.");
                return false;
            }
            if (ds_results.getCellData(i, "vehclNo") == "") {
                await $c.win.alert((i + 1) + "행의 차량번호는 필수 입력 항목 입니다.");
                return false;
            }
            if (ds_results.getCellData(i, "homeClntNo") == "") {
                await $c.win.alert((i + 1) + "행의 소속거래처는 필수 입력 항목 입니다.");
                return false;
            }
            if (ds_results.getCellData(i, "clntNo") == "" && ds_results.getCellData(i, "clntNm") == "") {
                await $c.win.alert((i + 1) + "행의 매니저코드/명  중 하나는 필수 입력 항목 입니다.");
                return false;
            }
            checkedCnt++;
        }
        if (ds_results.getRowStatus(i) == "U") {
            checkedCnt++;
        }
    }

    if (checkedCnt == 0) {
        await $c.win.alert("저장 할 데이터가 없습니다.");
        return false;
    }

    let chk = await $c.win.confirm(MSG_CM_CRM_001);
    if (chk) {
        await $c.sbm.execute(sbm_save);
    }
};

scwin.f_Apply = async function() {
    let checkedCnt = 0;

    for (let i = 0; i < ds_results.getRowCount(); i++) {
        if (ds_results.getRowStatus(i) == "U") {
            if (ds_results.getCellData(i, "uploadNo") == "") {
                await $c.win.alert("업로드 후 적용해주세요");
                return;
            }
            if (ds_results.getCellData(i, "rsltsMgntNo") != "") {
                await $c.win.alert("적용된 데이터는 재 적용할 수 없습니다.");
                return;
            }
            checkedCnt++;
        }
    }

    if (checkedCnt == 0) {
        await $c.win.alert("적용 할 데이터가 없습니다.");
        return false;
    }

    let chk = await $c.win.confirm("업로드 한 운송임을 등록하시겠습니까?");
    if (chk) {
        await $c.sbm.execute(sbm_apply);
    }
};

scwin.f_FieldClear = function() {
    ed_homeClntNo.setValue("");
    txt_homeClntNm.setValue("");
    ed_vehclNoCd.setValue("");
    txt_vehclNo.setValue("");
    udc_rsltsStdDt.setInitDate(scwin.vCurDate, scwin.vCurDate);
};

scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch, row) {
    switch (disGubun) {
        case 1:
            let condition1 = "";
            if (cnd_chb_repClntYn.getValue() != "") {
                condition1 = "RP";
            }
            udc_homeClnt.ilCommonPopUp(scwin.callbackHomeClnt,
                pCode, pName, pClose, '5', null, '150,170', null, condition1,
                null, null, null, null, null, pAllSearch, "거래처,거래처코드,거래처명");
            break;

        case 2:
            let pCode2 = ed_selpchItemCd ? ed_selpchItemCd.getValue() : pCode;
            let pName2 = txt_selpchItemNm ? txt_selpchItemNm.getValue() : pName;
            // TODO: ed_selpchItemCd / txt_selpchItemNm 은 검색조건 영역에 없으므로 UDC 또는 별도 컴포넌트 필요
            udc_homeClnt.ilCommonPopUp(scwin.callbackSelpchItem,
                pCode2, pName2, 'T', null, null, null, null, ',,,,,,',
                null, null, null, null, null, null, null);
            break;

        case 3:
            udc_vehclNo.ilCommonPopUp(scwin.callbackVehclNo,
                pCode, pName, pClose, null, null, null, null, null,
                "400", null, null, null, null, 'T', "차량번호,차량단축코드,차량번호");
            break;

        case 4:
            udc_vehclNo.ilCommonPopUp(function(rtnList) {
                scwin.callbackGridVehclNo(rtnList, row);
            },
                pCode, pName, pClose, null, null, null, null, null,
                "400", null, null, null, null, 'T', "차량번호,차량단축코드,차량번호");
            break;

        case 5:
            udc_homeClnt.ilCommonPopUp(function(rtnList) {
                scwin.callbackGridHomeClnt(rtnList, row);
            },
                pCode, pName, 'T', '5', null, '150,170', null, null,
                null, null, null, null, null, 'T', "거래처,거래처코드,거래처명");
            break;

        case 6:
            udc_clnt.ilCommonPopUp(function(rtnList) {
                scwin.callbackGridClnt(rtnList, row);
            },
                pCode, pName, 'T', '5', null, '150,170', null, null,
                null, null, null, null, null, 'T', "거래처,거래처코드,거래처명");
            break;

        case 7:
            udc_homeClnt.ilCommonPopUp(function(rtnList) {
                scwin.callbackGridSelpchItem(rtnList, row);
            },
                pCode, pName, 'T', null, null, null, null, ',,,,,,',
                null, null, null, null, null, null, null);
            break;

        default:
            break;
    }
};

scwin.callbackHomeClnt = async function(rtnList) {
    if (rtnList != null) {
        $c.gus.cfSetReturnValue(rtnList, ed_homeClntNo, txt_homeClntNm);
        dma_condition.set("upperClntNo", rtnList[5]);
    }
};

scwin.callbackSelpchItem = async function(rtnList) {
    if (rtnList != null && rtnList[0] != "N/A") {
        // TODO: ed_selpchItemCd / txt_selpchItemNm 컴포넌트가 body에 없으므로 수동 확인 필요
        $c.gus.cfSetReturnValue(rtnList, ed_selpchItemCd, txt_selpchItemNm);
    }
};

scwin.callbackVehclNo = async function(rtnList) {
    if (rtnList != null) {
        $c.gus.cfSetReturnValue(rtnList, ed_vehclNoCd, txt_vehclNo);
        ed_homeClntNo.setValue(rtnList[3]);
        txt_homeClntNm.setValue(rtnList[4]);
    }
};

scwin.callbackGridVehclNo = async function(rtnList, row) {
    if (rtnList != null) {
        ds_results.setCellData(row, "vehclNo", rtnList[1]);
        ds_results.setCellData(row, "homeClntNo", rtnList[3]);
        ds_results.setCellData(row, "homeClntNm", rtnList[4]);
        ds_results.setCellData(row, "clntNo", rtnList[5]);
        ds_results.setCellData(row, "clntNm", rtnList[6]);
        ds_results.setCellData(row, "eqCd", rtnList[7]);
        gr_results.setFocusedCell(row, "rsltsStdDt");
    }
};

scwin.callbackGridHomeClnt = async function(rtnList, row) {
    if (rtnList != null) {
        $c.gus.cfSetGridReturnValue(rtnList, ds_results, row, "homeClntNo", "homeClntNm");
    }
};

scwin.callbackGridClnt = async function(rtnList, row) {
    if (rtnList != null) {
        $c.gus.cfSetGridReturnValue(rtnList, ds_results, row, "clntNo", "clntNm");
    }
};

scwin.callbackGridSelpchItem = async function(rtnList, row) {
    if (rtnList != null && rtnList[0] != "N/A") {
        $c.gus.cfSetGridReturnValue(rtnList, ds_results, row, "selpchItemCd", "selpchItemNm");
        if (rtnList[2] == 0) {
            ds_results.setCellData(row, "taxnClsCd", "03");
            ds_results.setCellData(row, "clntVat", 0);
        } else {
            ds_results.setCellData(row, "taxnClsCd", "01");
        }
    }
};

scwin.f_chkOpenCommonPopUp = async function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }
    $c.gus.cfClearPairObj(pairObj);
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

scwin.f_addRow = async function() {
    let newRow = ds_results.insertRow();
    ds_results.setCellData(newRow, "chk", "1");
    ds_results.setCellData(newRow, "rsltsStdDt", ica_rsltsStdDtSt.getValue());
    // TODO: ed_selpchItemCd / txt_selpchItemNm 컴포넌트가 body에 없으므로 수동 확인 필요
    ds_results.setCellData(newRow, "sellClntNo", ed_homeClntNo.getValue());
    ds_results.setCellData(newRow, "sellClntNm", txt_homeClntNm.getValue());
    ds_results.setCellData(newRow, "vehclNo", txt_vehclNo.getValue());
    ds_results.setCellData(newRow, "dcsnYn", "1");
    spa_totalRow.setValue(ds_results.getTotalRow());
};

scwin.f_Delete = async function() {
    for (let i = 0; i < ds_results.getRowCount(); i++) {
        if (ds_results.getCellData(i, "rsltsMgntNo") != "") {
            await $c.win.alert("적용 후 실적번호가 생성된경우 삭제할 수 없습니다.");
            return;
        }
        if (ds_results.getCellData(i, "chk") == "1") {
            ds_results.removeRow(i);
            i--;
        }
    }
    let chk = await $c.win.confirm(MSG_CM_CRM_004);
    if (chk) {
        await $c.sbm.execute(sbm_delete);
    }
};

scwin.sbm_retrieve_submitdone = async function(e) {
    spa_totalRow.setValue(ds_results.getTotalRow());
    if (ds_results.getTotalRow() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
};

scwin.sbm_retrieve_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_save_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    scwin.f_Retrieve();
};

scwin.sbm_save_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_delete_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_004);
    scwin.f_Retrieve();
};

scwin.sbm_delete_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_apply_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_002);
    scwin.f_Retrieve();
};

scwin.sbm_apply_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.gr_results_onheaderclick = function(columnIndex, columnId) {
    if (columnId == "chk") {
        let checkAll = gr_results.getHeaderValue(columnId);
        for (let i = 0; i < ds_results.getRowCount(); i++) {
            if (checkAll == "T") {
                ds_results.setCellData(i, "chk", "1");
            } else {
                ds_results.setCellData(i, "chk", "0");
            }
        }
    }
};

scwin.ed_homeClntNo_onblur = function(e) {
    scwin.f_chkOpenCommonPopUp(ed_homeClntNo, txt_homeClntNm, 1);
};

scwin.ed_vehclNoCd_onblur = function(e) {
    scwin.f_chkOpenCommonPopUp(ed_vehclNoCd, txt_vehclNo, 3);
};

scwin.ed_clntNo_onblur = function(e) {
    scwin.f_chkOpenCommonPopUp(ed_clntNo, txt_clntNm, 1);
};
